import{c as i,Q as a,j as l,m as o}from"./chunks/framework.D9IbVcwA.js";const u=JSON.parse('{"title":"Init 线程","description":"","frontmatter":{},"headers":[],"relativePath":"document/kernel/proc/init.md","filePath":"document/kernel/proc/init.md","lastUpdated":1777209094000}'),t={name:"document/kernel/proc/init.md"};function n(r,e,c,d,h,s){return a(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="init-线程" tabindex="-1">Init 线程 <a class="header-anchor" href="#init-线程" aria-label="Permalink to &quot;Init 线程&quot;">​</a></h1><blockquote><p>里程碑: <code>028e_init_thread</code></p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>内核 init 线程，等价于 Linux PID 1。负责文件系统挂载和第一个用户进程 (shell) 的启动。将启动逻辑从 <code>kernel_main</code> 中分离，对齐 Linux init 线程模型。</p><h2 id="职责-kernel-proc-init-cpp" tabindex="-1">职责 (<code>kernel/proc/init.cpp</code>) <a class="header-anchor" href="#职责-kernel-proc-init-cpp" aria-label="Permalink to &quot;职责 (`kernel/proc/init.cpp`)&quot;">​</a></h2><ol><li>挂载文件系统 (ext2)</li><li>启动第一个用户进程 (shell 或 GUI 模式下的桌面)</li><li>作为孤儿进程的 reaper</li></ol><h2 id="kernel-main-启动流程" tabindex="-1">kernel_main 启动流程 <a class="header-anchor" href="#kernel-main-启动流程" aria-label="Permalink to &quot;kernel_main 启动流程&quot;">​</a></h2><ol><li>硬件初始化 (GDT, IDT, PIC, PIT, Serial...)</li><li><code>Scheduler::init()</code></li><li>创建 boot task → <code>kernel_init_thread()</code></li><li><code>run_first()</code> — 启动调度器</li><li>boot task 进入 yield+hlt 空闲回退</li></ol><h2 id="ahci-全局实例" tabindex="-1">AHCI 全局实例 <a class="header-anchor" href="#ahci-全局实例" aria-label="Permalink to &quot;AHCI 全局实例&quot;">​</a></h2><ul><li><code>AHCI::instance()</code> / <code>set_instance()</code> — 单例模式</li><li><code>main.cpp</code> 初始化后 <code>set_instance()</code>，<code>init.cpp</code> 通过 <code>instance()</code> 访问</li></ul><h2 id="统一内存布局" tabindex="-1">统一内存布局 <a class="header-anchor" href="#统一内存布局" aria-label="Permalink to &quot;统一内存布局&quot;">​</a></h2><ul><li><code>kernel/arch/x86_64/memory_layout.hpp</code> 定义 KMEM_HEAP / MMIO / STACK / DMA / EXT2_DMA</li><li>所有区域通过 base + size 计算，新增区域只需插入一行</li></ul><h2 id="关键修复" tabindex="-1">关键修复 <a class="header-anchor" href="#关键修复" aria-label="Permalink to &quot;关键修复&quot;">​</a></h2><ul><li>修复 <code>launch_first_user</code> 绕过调度器的问题</li><li>使用 placement new 避免 <code>AddressSpace</code> 析构器 <code>__dso_handle</code> 链接错误</li><li>修复内核栈虚拟地址覆盖 AHCI MMIO 映射导致 ext2 挂载失败</li></ul><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>kernel/proc/init.cpp</code> — init 线程实现</li><li><code>kernel/arch/x86_64/memory_layout.hpp</code> — 内存布局常量</li></ul>',16)])])}const _=i(t,[["render",n]]);export{u as __pageData,_ as default};
